import React, { useState, useRef, useCallback, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { getHealth, runDetection, runEnhance, downloadPDF, runVideoDetection } from "./api";

/* ─────────── nav items ─────────── */
const NAV = [
  { id: "scan",     icon: "🔬", label: "Anomaly Scan" },
  { id: "hull",     icon: "🚢", label: "Hull Inspect" },
  { id: "video",    icon: "🎬", label: "Video Analysis" },
  { id: "pipeline", icon: "🔧", label: "Pipeline" },
  { id: "cable",    icon: "⚡", label: "Sub-sea Cable" },
  { id: "dash",     icon: "📊", label: "Dashboard" },
  { id: "road",     icon: "🗺️", label: "Roadmap" },
];

/* page transition variants */
const pgVar = {
  enter:   { opacity: 0, y: 24 },
  center:  { opacity: 1, y: 0, transition: { duration: 0.4, ease: [0.4, 0, 0.2, 1] } },
  exit:    { opacity: 0, y: -16, transition: { duration: 0.2 } },
};

/* ═══════════════════════════════════════════════════
   Main App
   ═══════════════════════════════════════════════════ */
export default function App() {
  const [tab, setTab]         = useState("scan");
  const [health, setHealth]   = useState(null);
  const [file, setFile]       = useState(null);
  const [preview, setPreview] = useState(null);

  /* detection params */
  const [conf, setConf]       = useState(0.25);
  const [iou, setIou]         = useState(0.45);
  const [sevFilter, setSevFilter] = useState("All Detections");

  /* enhancement flags */
  const [clahe, setClahe]           = useState(true);
  const [claheClip, setClaheClip]   = useState(3.0);
  const [green, setGreen]           = useState(true);
  const [edge, setEdge]             = useState(false);
  const [turbLevel, setTurbLevel]   = useState(0.0);
  const [corrTurb, setCorrTurb]     = useState(true);
  const [marineSnow, setMarineSnow] = useState(false);

  /* mission info */
  const [vesselName, setVesselName]   = useState("");
  const [inspector, setInspector]     = useState("NautiCAI AutoScan v1.0");
  const [inspMode, setInspMode]       = useState("general");

  /* results */
  const [loading, setLoading]   = useState(false);
  const [detResult, setDetResult] = useState(null);
  const [enhResult, setEnhResult] = useState(null);
  const [error, setError]        = useState("");

  /* video */
  const [videoFile, setVideoFile] = useState(null);
  const [videoLoading, setVideoLoading] = useState(false);
  const [videoResult, setVideoResult]  = useState(null);

  /* health poll */
  useEffect(() => {
    getHealth().then(setHealth).catch(() => setHealth({ status: "offline" }));
    const t = setInterval(() => {
      getHealth().then(setHealth).catch(() => setHealth({ status: "offline" }));
    }, 30000);
    return () => clearInterval(t);
  }, []);

  /* file picker */
  const fileRef  = useRef();
  const videoRef = useRef();

  const handleFile = useCallback((f) => {
    if (!f) return;
    setFile(f);
    setPreview(URL.createObjectURL(f));
    setDetResult(null);
    setEnhResult(null);
    setError("");
  }, []);

  /* drag helpers */
  const onDragOver = (e) => { e.preventDefault(); e.currentTarget.classList.add("drag-over"); };
  const onDragLeave = (e) => { e.currentTarget.classList.remove("drag-over"); };
  const onDrop = (e) => { e.preventDefault(); e.currentTarget.classList.remove("drag-over"); handleFile(e.dataTransfer.files[0]); };

  /* ── Run Detection ── */
  const detect = async () => {
    if (!file) return;
    setLoading(true); setError("");
    try {
      const data = await runDetection(file, detParams());
      setDetResult(data);
    } catch (e) { setError(e.response?.data?.detail || e.message); }
    setLoading(false);
  };

  /* shared param builder */
  const detParams = () => ({
    conf_thr: conf, iou_thr: iou, mode: inspMode, sev_filter: sevFilter,
    use_clahe: clahe, clahe_clip: claheClip, use_green: green,
    use_edge: edge, turbidity_in: turbLevel, corr_turb: corrTurb, marine_snow: marineSnow,
  });
  const enhParams = () => ({
    use_clahe: clahe, clahe_clip: claheClip, use_green: green,
    use_edge: edge, turbidity_in: turbLevel, corr_turb: corrTurb, marine_snow: marineSnow,
  });

  /* ── Run Enhancement ── */
  const enhance = async () => {
    if (!file) return;
    setLoading(true); setError("");
    try {
      const data = await runEnhance(file, enhParams());
      setEnhResult(data);
    } catch (e) { setError(e.response?.data?.detail || e.message); }
    setLoading(false);
  };

  /* ── Run Both ── */
  const runBoth = async () => {
    if (!file) return;
    setLoading(true); setError("");
    try {
      const [det, enh] = await Promise.all([
        runDetection(file, detParams()),
        runEnhance(file, enhParams()),
      ]);
      setDetResult(det);
      setEnhResult(enh);
    } catch (e) { setError(e.response?.data?.detail || e.message); }
    setLoading(false);
  };

  /* ── PDF ── */
  const genPDF = () => {
    if (!file) return;
    downloadPDF(file, { ...detParams(), vessel_name: vesselName || "Unknown", inspector });
  };

  /* ── Video ── */
  const analyzeVideo = async () => {
    if (!videoFile) return;
    setVideoLoading(true); setError("");
    try {
      const data = await runVideoDetection(videoFile, { conf_thr: conf, iou_thr: iou, mode: inspMode, sample_n: 10, use_clahe: clahe, clahe_clip: claheClip, use_green: green, use_edge: edge, turbidity_in: turbLevel, corr_turb: corrTurb });
      setVideoResult(data);
    } catch (e) { setError(e.response?.data?.detail || e.message); }
    setVideoLoading(false);
  };

  const navigateTo = (id) => { setTab(id); setMobileNav(false); window.scrollTo({ top: 0, behavior: "smooth" }); };

  /* ═══════════ RENDER ═══════════ */
  return (
    <div className="site">
      {/* Video live wallpaper background */}
      <div className="video-bg">
        <video autoPlay muted loop playsInline className="video-bg__video">
          <source src="/ocean-bg.mp4" type="video/mp4" />
        </video>
        <div className="video-bg__overlay" />
      </div>

      {/* ════════ NAVBAR ════════ */}
      <nav className={`navbar ${tab !== "home" ? "navbar--solid" : ""}`}>
        <div className="nav-inner">
          <div className="nav-brand" onClick={() => navigateTo("home")} style={{ cursor: "pointer" }}>
            <img src="/nauticai-logo.png" alt="NautiCAI" className="nav-logo" />
            <div>
              <div className="nav-brand-name">NAUTICAI</div>
              <div className="nav-brand-tag">Underwater Intelligence</div>
            </div>
          </div>

          {/* Desktop nav links */}
          <div className="nav-links">
            {NAV.filter(n => n.id !== "home").map(n => (
              <button key={n.id} className={`nav-link ${tab === n.id ? "active" : ""}`}
                onClick={() => navigateTo(n.id)}>
                {n.label}
              </button>
            ))}
          </div>

          <div className="nav-actions">
            {tab !== "home" && (
              <button className="nav-settings-btn" onClick={() => setSettingsOpen(!settingsOpen)}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 00.33 1.82l.06.06a2 2 0 010 2.83 2 2 0 01-2.83 0l-.06-.06a1.65 1.65 0 00-1.82-.33 1.65 1.65 0 00-1 1.51V21a2 2 0 01-4 0v-.09A1.65 1.65 0 009 19.4a1.65 1.65 0 00-1.82.33l-.06.06a2 2 0 01-2.83-2.83l.06-.06A1.65 1.65 0 004.68 15a1.65 1.65 0 00-1.51-1H3a2 2 0 010-4h.09A1.65 1.65 0 004.6 9a1.65 1.65 0 00-.33-1.82l-.06-.06a2 2 0 012.83-2.83l.06.06A1.65 1.65 0 009 4.68a1.65 1.65 0 001-1.51V3a2 2 0 014 0v.09a1.65 1.65 0 001 1.51 1.65 1.65 0 001.82-.33l.06-.06a2 2 0 012.83 2.83l-.06.06A1.65 1.65 0 0019.4 9a1.65 1.65 0 001.51 1H21a2 2 0 010 4h-.09a1.65 1.65 0 00-1.51 1z"/>
                </svg>
                Settings
              </button>
            )}
            <span className="nav-status">
              <span className={`nav-dot ${health?.status === "ok" ? "dot-ok" : "dot-warn"}`} />
              {health?.status === "ok" ? "Online" : "Offline"}
            </span>
            <button className="btn btn-primary btn-sm" onClick={() => navigateTo("scan")}>
              Launch Platform
            </button>
            <button className="nav-hamburger" onClick={() => setMobileNav(!mobileNav)}>
              <span /><span /><span />
            </button>
          </div>
        </div>

        {/* Mobile nav dropdown */}
        {mobileNav && (
          <div className="nav-mobile">
            {NAV.map(n => (
              <button key={n.id} className={`nav-mobile-link ${tab === n.id ? "active" : ""}`}
                onClick={() => navigateTo(n.id)}>
                {n.label}
              </button>
            ))}
          </div>
        )}
      </nav>

      {/* ════════ SETTINGS DRAWER ════════ */}
      <div className={`settings-overlay ${settingsOpen ? "open" : ""}`} onClick={() => setSettingsOpen(false)} />
      <aside className={`settings-drawer ${settingsOpen ? "open" : ""}`}>
        <div className="sd-header">
          <h3>Detection Settings</h3>
          <button className="sd-close" onClick={() => setSettingsOpen(false)}>✕</button>
        </div>

        <div className="sd-section">
          <div className="sd-label">Detection Engine</div>
          <div className="ctrl">
            <div className="ctrl-header"><label>Confidence Threshold</label><span>{conf.toFixed(2)}</span></div>
            <input type="range" className="ctrl-slider" min={0.05} max={0.95} step={0.05}
              value={conf} onChange={e => setConf(+e.target.value)} />
          </div>
          <div className="ctrl">
            <div className="ctrl-header"><label>IoU Threshold</label><span>{iou.toFixed(2)}</span></div>
            <input type="range" className="ctrl-slider" min={0.1} max={0.9} step={0.05}
              value={iou} onChange={e => setIou(+e.target.value)} />
          </div>
        </div>

        <div className="sd-section">
          <div className="sd-label">Severity Filter</div>
          <select className="ctrl-select" value={sevFilter} onChange={e => setSevFilter(e.target.value)}>
            <option>All Detections</option><option>Critical Only</option>
            <option>High+</option><option>Medium+</option>
          </select>
        </div>

        <div className="sd-section">
          <div className="sd-label">Visibility Engine</div>
          <label className="ctrl-toggle">
            <span className="tgl"><input type="checkbox" checked={clahe} onChange={() => setClahe(!clahe)} />
              <span className="tgl-track" /><span className="tgl-knob" /></span>
            <span>CLAHE Enhancement</span>
          </label>
          {clahe && (
            <div className="ctrl">
              <div className="ctrl-header"><label>Clip Limit</label><span>{claheClip.toFixed(2)}</span></div>
              <input type="range" className="ctrl-slider" min={1.0} max={10.0} step={0.5}
                value={claheClip} onChange={e => setClaheClip(+e.target.value)} />
            </div>
          )}
          <label className="ctrl-toggle">
            <span className="tgl"><input type="checkbox" checked={green} onChange={() => setGreen(!green)} />
              <span className="tgl-track" /><span className="tgl-knob" /></span>
            <span>Green-Water Filter</span>
          </label>
          <label className="ctrl-toggle">
            <span className="tgl"><input type="checkbox" checked={edge} onChange={() => setEdge(!edge)} />
              <span className="tgl-track" /><span className="tgl-knob" /></span>
            <span>Edge Estimator</span>
          </label>
          <div className="ctrl">
            <div className="ctrl-header"><label>Turbidity Level</label><span>{turbLevel.toFixed(2)}</span></div>
            <input type="range" className="ctrl-slider" min={0} max={1.0} step={0.05}
              value={turbLevel} onChange={e => setTurbLevel(+e.target.value)} />
          </div>
          <label className="ctrl-toggle">
            <span className="tgl"><input type="checkbox" checked={corrTurb} onChange={() => setCorrTurb(!corrTurb)} />
              <span className="tgl-track" /><span className="tgl-knob" /></span>
            <span>Turbidity Correction</span>
          </label>
          <label className="ctrl-toggle">
            <span className="tgl"><input type="checkbox" checked={marineSnow} onChange={() => setMarineSnow(!marineSnow)} />
              <span className="tgl-track" /><span className="tgl-knob" /></span>
            <span>Marine Snow</span>
          </label>
        </div>

        <div className="sd-section">
          <div className="sd-label">Mission Info</div>
          <div className="ctrl">
            <div className="ctrl-header"><label>Vessel Name</label></div>
            <input type="text" className="ctrl-input" placeholder="e.g. MV Neptune Star"
              value={vesselName} onChange={e => setVesselName(e.target.value)} />
          </div>
          <div className="ctrl">
            <div className="ctrl-header"><label>Inspector</label></div>
            <input type="text" className="ctrl-input"
              value={inspector} onChange={e => setInspector(e.target.value)} />
          </div>
          <div className="ctrl">
            <div className="ctrl-header"><label>Inspection Mode</label></div>
            <select className="ctrl-select" value={inspMode} onChange={e => setInspMode(e.target.value)}>
              <option value="general">General</option><option value="hull">Hull</option>
              <option value="pipeline">Pipeline</option><option value="cable">Cable</option>
            </select>
          </div>
        </div>
      </aside>

      {/* ════════ MAIN CONTENT ════════ */}
      {tab === "home" ? (
        <HeroSection navigateTo={navigateTo} health={health} />
      ) : (
        <main className="site-main">
          <AnimatePresence mode="wait">
            <motion.div key={tab} className="page-wrap"
              variants={pgVar} initial="enter" animate="center" exit="exit">
              {tab === "scan" && <ScanPage
                file={file} preview={preview} fileRef={fileRef} handleFile={handleFile}
                onDragOver={onDragOver} onDragLeave={onDragLeave} onDrop={onDrop}
                detect={detect} enhance={enhance} runBoth={runBoth} genPDF={genPDF}
                loading={loading} detResult={detResult} enhResult={enhResult} error={error}
              />}
              {tab === "hull" && <HullPage
                file={file} preview={preview} fileRef={fileRef} handleFile={handleFile}
                onDragOver={onDragOver} onDragLeave={onDragLeave} onDrop={onDrop}
                detect={detect} genPDF={genPDF} loading={loading} detResult={detResult} error={error}
              />}
              {tab === "video" && <VideoPage
                videoFile={videoFile} videoRef={videoRef} setVideoFile={setVideoFile}
                onDragOver={onDragOver} onDragLeave={onDragLeave}
                analyzeVideo={analyzeVideo} genPDF={genPDF} file={file} videoLoading={videoLoading}
                videoResult={videoResult} error={error}
              />}
              {tab === "pipeline" && <PipelinePage
                file={file} preview={preview} handleFile={handleFile}
                onDragOver={onDragOver} onDragLeave={onDragLeave} onDrop={onDrop}
                detect={detect} loading={loading} detResult={detResult} error={error}
              />}
              {tab === "cable" && <CablePage
                file={file} preview={preview} handleFile={handleFile}
                onDragOver={onDragOver} onDragLeave={onDragLeave} onDrop={onDrop}
                detect={detect} loading={loading} detResult={detResult} error={error}
              />}
              {tab === "dash" && <DashPage detResult={detResult} />}
              {tab === "road" && <RoadmapPage />}
            </motion.div>
          </AnimatePresence>
        </main>
      )}

      {/* ════════ FOOTER ════════ */}
      <footer className="site-footer">
        <div className="footer-inner">
          <div className="footer-col footer-brand-col">
            <div className="footer-brand">
              <img src="/nauticai-logo.png" alt="NautiCAI" />
              <span>NAUTICAI</span>
            </div>
            <p className="footer-tagline">AI-powered underwater inspection for the maritime industry. Protecting critical subsea infrastructure.</p>
          </div>
          <div className="footer-col">
            <h4>Platform</h4>
            <button onClick={() => navigateTo("scan")}>Anomaly Detection</button>
            <button onClick={() => navigateTo("hull")}>Hull Inspection</button>
            <button onClick={() => navigateTo("pipeline")}>Pipeline Analysis</button>
            <button onClick={() => navigateTo("cable")}>Cable Monitoring</button>
          </div>
          <div className="footer-col">
            <h4>Company</h4>
            <button onClick={() => navigateTo("road")}>Roadmap</button>
            <a href="https://www.nauticai-ai.com" target="_blank" rel="noreferrer">Website</a>
            <button onClick={() => navigateTo("dash")}>Dashboard</button>
          </div>
          <div className="footer-col">
            <h4>Technology</h4>
            <span>YOLOv8 Detection</span>
            <span>FastAPI Backend</span>
            <span>React Frontend</span>
            <span>Google Cloud</span>
          </div>
        </div>
        <div className="footer-bottom">
          <span>© 2025 NautiCAI Pte Ltd · Singapore</span>
          <span className="footer-sep">·</span>
          <a href="https://www.nauticai-ai.com" target="_blank" rel="noreferrer">www.nauticai-ai.com</a>
        </div>
      </footer>
    </div>
  );
}

/* ═══════════════════════════════════════════════════
   HERO: Landing Page
   ═══════════════════════════════════════════════════ */
function HeroSection({ navigateTo, health }) {
  const features = [
    { icon: "🔬", title: "Anomaly Detection", desc: "YOLOv8-powered object detection for underwater infrastructure anomalies, corrosion, and marine growth.", link: "scan" },
    { icon: "🚢", title: "Hull Inspection", desc: "9-zone vessel hull analysis covering propellers, rudders, sea-chests, and thruster systems.", link: "hull" },
    { icon: "🎬", title: "Video Analysis", desc: "Frame-by-frame ROV/AUV footage processing with cross-frame aggregation and risk scoring.", link: "video" },
    { icon: "🔧", title: "Pipeline Monitoring", desc: "Detect corrosion, dents, free-spans and coating damage on subsea pipeline infrastructure.", link: "pipeline" },
    { icon: "⚡", title: "Cable Integrity", desc: "Monitor submarine cable condition — abrasion, burial depth, and marine growth assessment.", link: "cable" },
    { icon: "📊", title: "Analytics Dashboard", desc: "Real-time threat gauges, severity breakdowns, sonar visualization, and mission grading.", link: "dash" },
  ];

  return (
    <>
      {/* Hero */}
      <section className="hero">
        <div className="hero-content">
          <motion.div initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.7 }}>
            <div className="hero-chip">
              <span className={`nav-dot ${health?.status === "ok" ? "dot-ok" : "dot-warn"}`} />
              AI-Powered Maritime Inspection Platform
            </div>
            <h1 className="hero-title">
              Deep-Sea Anomaly<br />
              <span className="hero-accent">Detection & Intelligence</span>
            </h1>
            <p className="hero-subtitle">
              Protecting critical underwater infrastructure with computer vision. 
              Real-time anomaly detection, visibility enhancement, and automated reporting 
              for maritime inspection teams.
            </p>
            <div className="hero-actions">
              <button className="btn btn-primary btn-lg" onClick={() => navigateTo("scan")}>
                Start Inspection →
              </button>
              <button className="btn btn-outline btn-lg" onClick={() => navigateTo("road")}>
                View Roadmap
              </button>
            </div>
            <div className="hero-stats">
              <div className="hero-stat">
                <div className="hero-stat-val">6</div>
                <div className="hero-stat-label">Inspection Modules</div>
              </div>
              <div className="hero-stat-sep" />
              <div className="hero-stat">
                <div className="hero-stat-val">YOLOv8</div>
                <div className="hero-stat-label">Detection Engine</div>
              </div>
              <div className="hero-stat-sep" />
              <div className="hero-stat">
                <div className="hero-stat-val">9</div>
                <div className="hero-stat-label">Hull Zones</div>
              </div>
              <div className="hero-stat-sep" />
              <div className="hero-stat">
                <div className="hero-stat-val">PDF</div>
                <div className="hero-stat-label">Auto Reports</div>
              </div>
            </div>
          </motion.div>
        </div>
      </section>

      {/* Features */}
      <section className="features-section">
        <div className="features-inner">
          <div className="features-header">
            <div className="section-crumb">Capabilities</div>
            <h2 className="features-title">Comprehensive Underwater Inspection</h2>
            <p className="features-desc">
              From hull biofouling to subsea cable abrasion — our platform covers every aspect of underwater asset integrity.
            </p>
          </div>
          <div className="features-grid">
            {features.map(f => (
              <motion.div key={f.link} className="feature-card" whileHover={{ y: -6, scale: 1.02 }}
                onClick={() => navigateTo(f.link)} style={{ cursor: "pointer" }}>
                <div className="feature-icon">{f.icon}</div>
                <h3 className="feature-name">{f.title}</h3>
                <p className="feature-desc">{f.desc}</p>
                <span className="feature-link">Explore →</span>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA banner */}
      <section className="cta-section">
        <div className="cta-inner">
          <h2>Ready to inspect?</h2>
          <p>Upload an image and get AI-powered anomaly detection results in seconds.</p>
          <button className="btn btn-primary btn-lg" onClick={() => navigateTo("scan")}>
            Launch Platform →
          </button>
        </div>
      </section>
    </>
  );
}

/* ═══════════════════════════════════════════════════
   PAGE: Anomaly Scan
   ═══════════════════════════════════════════════════ */
function ScanPage({ file, preview, fileRef, handleFile, onDragOver, onDragLeave, onDrop,
                    detect, enhance, runBoth, genPDF, loading, detResult, enhResult, error }) {
  return (
    <>
      <div className="section-header fade-up">
        <div className="section-crumb">Module · Anomaly Detection</div>
        <h2 className="section-title">Underwater Anomaly Scan</h2>
        <p className="section-desc">
          Upload an underwater image to run YOLOv8 anomaly detection, visibility enhancement, and generate PDF reports.
        </p>
        <div className="section-rule" />
      </div>

      <div className="card mb-20">
        <div className="card-title">Anomaly Scan Workflow</div>
        <WorkflowStrip steps={[
          { icon: "📷", label: "Upload",   sub: "Image / Batch" },
          { icon: "✨", label: "Enhance",  sub: "CLAHE + Turbidity" },
          { icon: "🔬", label: "Detect",   sub: "YOLOv8 Inference" },
          { icon: "🏷️", label: "Classify", sub: "Severity Map" },
          { icon: "📄", label: "Report",   sub: "PDF Generation" },
        ]} />
      </div>

      {/* Upload */}
      <div className="card mb-20">
        <div className="card-title">Image Upload</div>
        <div className="dropzone" onClick={() => fileRef.current?.click()}
             onDragOver={onDragOver} onDragLeave={onDragLeave} onDrop={onDrop}>
          <div className="dz-icon">📷</div>
          <div className="dz-label">
            {preview ? "Click or drop to replace" : "Drop underwater image here, or click to browse"}
          </div>
          <div className="dz-hint">Supported: JPG, PNG, BMP · Max 20 MB</div>
          {file && <div className="dz-file">✓ {file.name}</div>}
        </div>
        <input ref={fileRef} type="file" accept="image/*" hidden
          onChange={e => handleFile(e.target.files[0])} />
      </div>

      {/* Action buttons */}
      <div className="row mb-20" style={{ gap: 10, flexWrap: "wrap" }}>
        <button className="btn btn-primary" disabled={!file || loading} onClick={detect}>
          {loading ? <span className="spinner" /> : null}
          Run Detection
        </button>
        <button className="btn btn-ghost" disabled={!file || loading} onClick={enhance}>
          Enhance Visibility
        </button>
        <button className="btn btn-primary" disabled={!file || loading} onClick={runBoth}>
          Detect + Enhance
        </button>
        <button className="btn btn-ghost" disabled={!file} onClick={genPDF}>
          📄 PDF Report
        </button>
      </div>

      {error && <div className="alert alert-warn">⚠️ {error}</div>}

      {/* Results */}
      {!detResult && !enhResult && preview && (
        <div className="card">
          <div className="card-title">Original Image</div>
          <div className="image-frame">
            <img src={preview} alt="original" />
          </div>
        </div>
      )}

      {detResult && <DetectionResults data={detResult} preview={preview} />}
      {enhResult && <EnhancementResults data={enhResult} />}
    </>
  );
}

/* ═══════════════════════════════════════════════════
   PAGE: Hull Inspect
   ═══════════════════════════════════════════════════ */
function HullPage({ file, preview, fileRef, handleFile, onDragOver, onDragLeave, onDrop,
                    detect, genPDF, loading, detResult, error }) {
  return (
    <>
      <div className="section-header fade-up">
        <div className="section-crumb">Module · Hull Inspection</div>
        <h2 className="section-title">Hull & Structure Analysis</h2>
        <p className="section-desc">
          Inspect vessel hulls for biofouling, marine growth, corrosion, and structural anomalies across 9 zones.
        </p>
        <div className="section-rule" />
      </div>

      <div className="card mb-20">
        <div className="card-title">Hull Inspection Workflow</div>
        <WorkflowStrip steps={[
          { icon: "📤", label: "Upload",   sub: "Hull Image" },
          { icon: "🗺️", label: "Zone Map", sub: "9-Zone Classification" },
          { icon: "🔍", label: "Detect",   sub: "Biofouling + Corrosion" },
          { icon: "⚠️", label: "Severity", sub: "Risk Assessment" },
          { icon: "📄", label: "Report",   sub: "PDF Export" },
        ]} />
      </div>

      <div className="card mb-20">
        <div className="card-title">Upload Hull Image</div>
        <div className="dropzone" onClick={() => fileRef.current?.click()}
